_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec3 blur = lum(GetBlur1(fract(vUv)))*crumple;
vec2 hor = vec2 (uTexSize.z,0)*8*blur;
vec2 ver = vec2 (0,uTexSize.w)*8*blur;
float dx = lum(texture(sampler_main,vUv+hor) - texture(sampler_main,vUv-hor));
float dy = lum(texture(sampler_main,vUv+ver) - texture(sampler_main,vUv-ver));
vec2 dz = vec2 (dx + (vUv.x-.5)*.0,dy+.0);

uv1 = vec2 (abs(vUv.x-.5),vUv.y-.5);

float teeth = sin((uv1.x)*142+1.5*sign(uv1.y-mouth_y))-mopen*.008/abs(uv1.y-mouth_y);

float eyes = clamp01(eyerad/length(uv1-eyepos));
eyes = pow(eyes,4);
float mouth = clamp01(.05/sqrt(uv1.x*uv1.x*mwidth + (.05/(.01+mshape*uv1.x))*(1+q15)/mopen*pow(uv1.y-mouth_y,2)));
mouth = pow(mouth,3);
mod = eyes + mouth*mopen;
hole = pow(max(eyes,mouth),1);

vec3 eyeball = clamp01(cos(1.4/eyerad*length(uv1-eyepos)))/3*(2-direct)*roam_sin*2;
eyeball = eyeball - (length(uv1-eyepos-.02*vec2(q9*0,q10-eyepos.y)) < .01*q15);

noise3 = lum(texture(sampler_noise_lq,uv1))+.5;
uv1 += mod/4;
teeth *= (mouth);

vec2 ang2= texture(sampler_noise_hq,uv1/4+uTime/400).xy;
uv6 = uv1 + .5*(uv1*4*ang2);
float mus = cos(uv6.y*18)+(sin(uv6.x*18));
noise2 = abs(mus)/6*(1+abs(crumple/16))+.2;
noise2 *= vec3 (1,.9,.8);
noise2 = mix(noise2,teeth,mouth);
noise2 = mix(noise2,eyeball,eyes);
blur2 = GetBlur2(fract(noise3));

vec3 crisp = GetPixel(fract(vUv+dz*.003));
crisp += -0.0*blur2 - length(dz)*.1;

ret = crisp * (.99-hole/2*direct) -  .01 + noise2*(.045+hole*direct)  ;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv4 = vUv-.5+vec2(q9,q10);

float water = texture(sampler_noise_mq,vUv/2+uTime/5);
uv1 = (vUv-.5)*uAspect.xy + water *.0;
uv3 = rs(uv1);
float rad1 = clamp01(.2/dist/length(uv1.x+q9));
float rad2 = clamp01(.05/dist/length(uv1+vec2(q9,q10)));
beast = texture(sampler_main, uv3)*rad1;
bcopy = texture(sampler_main, rs2(uv1))*clamp01(1-8*lum(beast))*rad2/2;;

float light = 2*clamp01(.05/length(uv1+lightpos+2*dz(uv3)));
float flatlight = clamp01((1+q15)*.5/dist/length(uv1+lightpos));

vec2 uv5 = normalize(uv1+vec2(.1,.1)+lightpos)*1+lightpos;
vec3 ray = clamp01(GetPixel(rs(uv5)));

beast *= pow(flatlight,2)*.7;
beast += lum(beast)*light*light *pow(flatlight,2) ;
//beast = mix(beast,.2*vec3(.5,.5,1)*flatlight,4*abs(uv1.x));
ret = (beast+bcopy*flatlight);
ret = mix(clamp01(flatlight*vec3(q22,0,0)),ret, vis);


  fragColor = ret;
}
